# Math utilities module with functions and a static calculator class

PI: float = 3.14159

def square(x: float) -> float:
    return x * x

def cube(x: float) -> float:
    return x * x * x

def clamp(value: float, min_val: float, max_val: float) -> float:
    if value < min_val:
        return min_val
    if value > max_val:
        return max_val
    return value

class Calculator:
    @static
    def add(a: float, b: float) -> float:
        return a + b

    @static
    def subtract(a: float, b: float) -> float:
        return a - b

    @static
    def multiply(a: float, b: float) -> float:
        return a * b

    @static
    def divide(a: float, b: float) -> float:
        return a / b

class Statistics:
    values: list[float]

    def __init__(self, values: list[float]):
        self.values = values

    def mean(self) -> float:
        total: float = 0.0
        for v in self.values:
            total = total + v
        return total / len(self.values)

    def max_value(self) -> float:
        max_val: float = self.values[0]
        for v in self.values:
            if v > max_val:
                max_val = v
        return max_val

    def min_value(self) -> float:
        min_val: float = self.values[0]
        for v in self.values:
            if v < min_val:
                min_val = v
        return min_val

