# Shapes module with inheritance from math_utils

from math_utils import PI, square, Calculator

class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "A shape named " + self.name

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return Calculator.multiply(self.width, self.height)

    @override
    def perimeter(self) -> float:
        return Calculator.multiply(2.0, Calculator.add(self.width, self.height))

    @override
    def describe(self) -> str:
        return "Rectangle " + self.name + ": " + str(self.width) + " x " + str(self.height)

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return Calculator.multiply(PI, square(self.radius))

    @override
    def perimeter(self) -> float:
        return Calculator.multiply(Calculator.multiply(2.0, PI), self.radius)

    @override
    def describe(self) -> str:
        return "Circle " + self.name + " with radius " + str(self.radius)

def compute_shape_stats(shape: Shape) -> tuple[area: float, perimeter: float]:
    return (area=shape.area(), perimeter=shape.perimeter())
